const pollMs = 50;
const arrowNames = new Set(['arrow', 'spectral_arrow', 'tipped_arrow']);
const hostileNames = new Set(['zombie', 'skeleton', 'creeper', 'spider', 'husk', 'drowned', 'stray', 'witch', 'enderman', 'piglin', 'hoglin', 'zoglin']);
const getArrowCount = function () {
  return bot.inventory.items().filter(function (item) {
    return arrowNames.has(item.name);
  }).reduce(function (total, item) {
    return total + item.count;
  }, 0);
};
const findTarget = function () {
  if (args.targetEntityId) {
    const e = bot.entities[args.targetEntityId];
    if (e && e.isValid && e.position.distanceTo(bot.entity.position) < args.maxSearchRadiusBlocks) return e;
  }
  return bot.nearestEntity(function (e) {
    if (!e || !e.isValid || e.position.distanceTo(bot.entity.position) > args.maxSearchRadiusBlocks) return false;
    if (e.type === 'hostile' || e.kind === 'Hostile mobs' || hostileNames.has(e.name)) return true;
    return false;
  });
};
if (!bot.entity || bot.health <= 0) return '<UNSAFE>: Bot is dead.';
const bow = bot.inventory.items().find(function (item) { return item.name === 'bow'; });
if (!bow) return '<NO ITEM>: No bow found in inventory.';
if (getArrowCount() <= 0) return '<NO ITEM>: No arrows found in inventory.';
const initialTarget = findTarget();
if (!initialTarget) return '<NO TARGET>: No hostiles within ' + args.maxSearchRadiusBlocks + ' blocks.';
startBackgroundSkill(bot, 'attack_with_bow', async function (token) {
  let currentTarget = initialTarget;
  let shotsFired = 0;
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);
  try {
    while (canContinueBotAction(bot, token) && shotsFired < args.maxShots) {
      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      if (!currentTarget || !currentTarget.isValid || currentTarget.health <= 0) {
        currentTarget = findTarget();
        if (!currentTarget) return;
      }
      const distance = bot.entity.position.distanceTo(currentTarget.position);
      const isLowHealth = bot.health <= args.kiteHealthThreshold;
      const targetRange = isLowHealth ? args.engageDistanceBlocks + 5 : args.engageDistanceBlocks;
      if (distance > targetRange + 2) {
        bot.pathfinder.setGoal(new goals.GoalFollow(currentTarget, targetRange));
      } else if (distance < targetRange - 2) {
        const pos = bot.entity.position.clone().add(bot.entity.position.clone().subtract(currentTarget.position).normalize().multiplyScalar(5));
        bot.pathfinder.setGoal(new goals.GoalNear(pos.x, pos.y, pos.z, 1));
      } else {
        if (bot.pathfinder.goal) bot.pathfinder.setGoal(null);
      }
      const weapon = bot.inventory.items().find(function (i) { return i.name === 'bow'; });
      if (!weapon || getArrowCount() <= 0) return;
      if (bot.heldItem?.name !== 'bow') await bot.equip(weapon, 'hand');
      const aimPos = currentTarget.position.offset(0, Math.max(0.6, (currentTarget.height || 1.8) * 0.75), 0);
      await bot.lookAt(aimPos, true);
      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      bot.activateItem();
      const drawn = await waitForActiveMs(bot, token, args.holdDrawMs, pollMs);
      bot.deactivateItem();
      if (drawn) shotsFired++;
      await waitForActiveMs(bot, token, 400, pollMs);
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.deactivateItem();
  }
});
return '<STARTED>: Engaging nearest hostile with bow from context health ' + bot.health + '.';
